import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PipelineStage {
  stage: string;
  candidates: number;
}

interface PipelineData {
  pipeline: {
    stages: PipelineStage[];
    timeToHire: {
      averageDays: number;
      fastestDays: number;
      slowestDays: number;
    };
    openPositions: number;
  };
}

export default function Widget() {
  const data = response.data as PipelineData;
  const { stages, timeToHire, openPositions } = data.pipeline;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Recruitment Pipeline
            </Typography>
            <Typography variant="h6" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              Open Positions: {openPositions}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: stages.map(stage => stage.candidates),
                  color: '#3B82F6',
                  label: 'Candidates',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: stages.map(stage => stage.stage),
                  id: 'stages',
                },
              ]}
              yAxis={[{ id: 'candidates' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="stages"
                tickLabelStyle={{ fontSize: 10, fill: '#D1D5DB' }}
              />
              <ChartsYAxis
                axisId="candidates"
                tickLabelStyle={{ fontSize: 10, fill: '#D1D5DB' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              Time to Hire
            </Typography>
            <Stack direction="row" spacing={3}>
              <Box>
                <Typography variant="caption" sx={{ color: '#94A3B8' }}>
                  Average
                </Typography>
                <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 500 }}>
                  {timeToHire.averageDays} days
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" sx={{ color: '#94A3B8' }}>
                  Fastest
                </Typography>
                <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 500 }}>
                  {timeToHire.fastestDays} days
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" sx={{ color: '#94A3B8' }}>
                  Slowest
                </Typography>
                <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 500 }}>
                  {timeToHire.slowestDays} days
                </Typography>
              </Box>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
